const githubToken = process.env.GITHUB_TOKEN || '';

if (!githubToken) {
  return [{ json: { applications: [], skip_reason: 'No GITHUB_TOKEN' } }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json'
};

async function getFileContent(path) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + path,
      headers: headers
    });
    return Buffer.from(resp.content, 'base64').toString('utf-8');
  } catch(e) {
    return null;
  }
}

async function listFolder(path) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + path,
      headers: headers
    });
    return Array.isArray(resp) ? resp : [];
  } catch(e) {
    return [];
  }
}

// Fetch active applications (Job_Applications/Active folder)
const activeFiles = await listFolder('Obsidian_Vault/Job_Applications/Active');
const waitingFiles = await listFolder('Obsidian_Vault/Job_Applications/Waiting');
const allFiles = [...activeFiles, ...waitingFiles];

const applications = [];
const today = new Date();

for (const file of allFiles) {
  if (file.type === 'file' && file.name.endsWith('.md') && file.name !== '.gitkeep') {
    const content = await getFileContent(file.path);
    if (!content) continue;

    // Parse frontmatter
    const frontmatterMatch = content.match(/^---([\s\S]*?)---/);
    if (!frontmatterMatch) continue;

    const frontmatter = {};
    const lines = frontmatterMatch[1].split('\n');
    lines.forEach(line => {
      const match = line.match(/^(\w+):\s*(.+)$/);
      if (match) frontmatter[match[1].trim()] = match[2].trim();
    });

    const appliedDate = frontmatter.applied_date ? new Date(frontmatter.applied_date) : null;
    if (!appliedDate) continue;

    const daysSinceApplied = Math.floor((today - appliedDate) / (1000 * 60 * 60 * 24));
    const status = frontmatter.status || 'applied';
    const companyName = frontmatter.company || file.name.replace('.md', '');
    const jobTitle = frontmatter.role || 'Unknown Role';

    // Determine if follow-up is due
    let followUpDue = false;
    let followUpType = '';

    if (status === 'applied' && daysSinceApplied === 3) {
      followUpDue = true;
      followUpType = 'day_3_application';
    } else if (status === 'applied' && daysSinceApplied === 7) {
      followUpDue = true;
      followUpType = 'day_7_application';
    } else if (status === 'phone_screen_scheduled') {
      const phoneScreenDate = frontmatter.phone_screen_date ? new Date(frontmatter.phone_screen_date) : null;
      if (phoneScreenDate) {
        const daysSincePhoneScreen = Math.floor((today - phoneScreenDate) / (1000 * 60 * 60 * 24));
        if (daysSincePhoneScreen === 1) {
          followUpDue = true;
          followUpType = 'post_phone_screen';
        }
      }
    } else if (status === 'technical_scheduled') {
      const technicalDate = frontmatter.technical_date ? new Date(frontmatter.technical_date) : null;
      if (technicalDate) {
        const daysSinceTechnical = Math.floor((today - technicalDate) / (1000 * 60 * 60 * 24));
        if (daysSinceTechnical === 1) {
          followUpDue = true;
          followUpType = 'post_technical';
        }
      }
    } else if (status === 'rejected' && daysSinceApplied === 90) {
      followUpDue = true;
      followUpType = '90_day_checkin';
    }

    if (followUpDue) {
      applications.push({
        company_name: companyName,
        job_title: jobTitle,
        status: status,
        follow_up_type: followUpType,
        days_since_applied: daysSinceApplied,
        applied_date: frontmatter.applied_date,
        hiring_manager_email: frontmatter.hiring_manager_email || '',
        file_path: file.path
      });
    }
  }
}

return applications.map(app => ({ json: app }));

const appData = $input.item.json;

async function callOllama(prompt) {
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const resp = await $helpers.httpRequest({
        method: 'POST',
        url: 'http://ollama:11434/api/generate',
        headers: { 'Content-Type': 'application/json' },
        body: { model: 'llama3.2', prompt: prompt, stream: false }
      });
      return (resp && resp.response) ? resp.response : '[No response]';
    } catch (e) {
      if (attempt === 3) return '[Ollama Error: ' + e.message + ']';
      await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000));
    }
  }
}

const followUpType = appData.follow_up_type;
const companyName = appData.company_name;
const jobTitle = appData.job_title;

let emailContext = '';
let subjectLine = '';

if (followUpType === 'day_3_application') {
  emailContext = 'This is a 3-day follow-up after submitting an application. Keep it brief (3 sentences). Express continued interest. Ask about timeline.';
  subjectLine = 'Following up on my application - ' + jobTitle + ' at ' + companyName;
} else if (followUpType === 'day_7_application') {
  emailContext = 'This is a 7-day follow-up after submitting an application. Brief (3 sentences). Reiterate one specific reason for interest. Ask if they need more information.';
  subjectLine = 'Re: ' + jobTitle + ' application - checking in';
} else if (followUpType === 'post_phone_screen') {
  emailContext = 'This is a thank-you email sent 24 hours after a phone screen. Express genuine enthusiasm from the conversation. Reference something specific discussed. Ask about next steps.';
  subjectLine = 'Thank you - ' + jobTitle + ' phone screen at ' + companyName;
} else if (followUpType === 'post_technical') {
  emailContext = 'This is a thank-you email sent 24 hours after a technical interview. Express enthusiasm for the technical challenges discussed. Optionally add a brief insight from the technical discussion. Ask about timeline.';
  subjectLine = 'Thank you - ' + jobTitle + ' technical interview at ' + companyName;
} else if (followUpType === '90_day_checkin') {
  emailContext = 'This is an optional 90-day check-in after a rejection. Very brief. Note what you've learned/built since. Express continued interest in the company. Ask if there are relevant openings.';
  subjectLine = 'Checking in - opportunities at ' + companyName;
}

const prompt = 'Write a personalized follow-up email for ' + companyName + ' regarding the ' + jobTitle + ' position. ' + emailContext + ' Sign as Odeliya Charitonova with email odeliya.charitonova.dev@gmail.com. Be authentic and professional, not generic.';

const emailBody = await callOllama(prompt);

return [{
  json: {
    ...appData,
    email_subject: subjectLine,
    email_body: emailBody,
    generated_at: new Date().toISOString()
  }
}];

const appData = $input.item.json;
const githubToken = process.env.GITHUB_TOKEN || '';

if (!githubToken) {
  return [{ json: { ...appData, log_status: 'skipped' } }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json'
};

async function apiRequest(method, path, body) {
  return await $helpers.httpRequest({
    method: method,
    url: 'https://api.github.com' + path,
    headers: headers,
    body: body
  });
}

try {
  // Get current file content
  let existingContent = '';
  let existingFileSha = null;

  const logPath = appData.file_path ? appData.file_path.replace('.md', '-communication-log.md') :
    'Obsidian_Vault/Job_Applications/Active/' + appData.company_name + '-communication-log.md';

  try {
    const fileData = await apiRequest('GET', '/repos/' + owner + '/' + repo + '/contents/' + logPath);
    existingContent = Buffer.from(fileData.content, 'base64').toString('utf-8');
    existingFileSha = fileData.sha;
  } catch(e) {
    existingContent = '# Communication Log - ' + appData.company_name + '\n\n';
  }

  // Append new log entry
  const today = new Date().toISOString().split('T')[0];
  const logEntry = '- **' + today + '** | Sent: ' + appData.follow_up_type.replace(/_/g, ' ') + ' follow-up | Subject: ' + appData.email_subject + '\n';
  const updatedContent = existingContent + logEntry;

  // Commit the update
  const updateBody = {
    message: 'Update communication log: ' + appData.company_name + ' ' + appData.follow_up_type,
    content: Buffer.from(updatedContent).toString('base64'),
    branch: 'main'
  };
  if (existingFileSha) updateBody.sha = existingFileSha;

  await apiRequest('PUT', '/repos/' + owner + '/' + repo + '/contents/' + logPath, updateBody);

  return [{ json: { ...appData, log_status: 'updated', log_path: logPath } }];
} catch(e) {
  console.error('Error updating communication log:', e.message);
  return [{ json: { ...appData, log_status: 'error', log_error: e.message } }];
}
